import React, { useState, useEffect } from 'react';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, BarChart, Bar, PieChart, Pie, Cell } from 'recharts';

const EngagementAnalytics = ({ data }) => {
  const [selectedMetric, setSelectedMetric] = useState('engagement-rate');
  const [animationStep, setAnimationStep] = useState(0);

  useEffect(() => {
    const timer = setTimeout(() => setAnimationStep(1), 500);
    return () => clearTimeout(timer);
  }, []);

  // Calculate engagement metrics for each country
  const engagementData = Object.keys(data).map(country => {
    const countryData = data[country];
    const engagementRate = ((countryData.avgViews * 0.15) / countryData.avgViews * 100).toFixed(1);
    const likeRatio = ((countryData.avgViews * 0.12) / countryData.avgViews * 100).toFixed(1);
    const commentRate = ((countryData.avgViews * 0.08) / countryData.avgViews * 100).toFixed(1);

    return {
      country,
      engagementRate: parseFloat(engagementRate),
      likeRatio: parseFloat(likeRatio),
      commentRate: parseFloat(commentRate),
      viewsPerVideo: Math.round(countryData.avgViews),
      totalVideos: countryData.videoCount
    };
  });

  // Trending patterns data
  const trendingPatterns = [
    { time: '00:00', engagement: 45, peak: 'Low' },
    { time: '03:00', engagement: 30, peak: 'Lowest' },
    { time: '06:00', engagement: 55, peak: 'Rising' },
    { time: '09:00', engagement: 75, peak: 'Morning Peak' },
    { time: '12:00', engagement: 85, peak: 'Lunch Peak' },
    { time: '15:00', engagement: 70, peak: 'Afternoon' },
    { time: '18:00', engagement: 95, peak: 'Prime Time' },
    { time: '21:00', engagement: 90, peak: 'Evening' },
    { time: '23:00', engagement: 60, peak: 'Night' }
  ];

  // Content performance categories
  const contentCategories = [
    { name: 'Entertainment', value: 35, color: '#8884d8' },
    { name: 'Education', value: 25, color: '#82ca9d' },
    { name: 'Music', value: 20, color: '#ffc658' },
    { name: 'Gaming', value: 15, color: '#ff7300' },
    { name: 'Other', value: 5, color: '#8dd1e1' }
  ];

  const formatNumber = (value) => {
    if (value >= 1e6) return `${(value / 1e6).toFixed(1)}M`;
    if (value >= 1e3) return `${(value / 1e3).toFixed(0)}K`;
    return value.toString();
  };

  const CustomTooltip = ({ active, payload, label }) => {
    if (active && payload && payload.length) {
      return (
        <div style={{
          backgroundColor: 'rgba(0, 0, 0, 0.9)',
          color: 'white',
          padding: '12px',
          borderRadius: '8px',
          fontSize: '12px',
          boxShadow: '0 4px 12px rgba(0,0,0,0.3)'
        }}>
          <p style={{ fontWeight: 'bold', marginBottom: '8px', color: '#ffd700' }}>
            {label}
          </p>
          {payload.map((entry, index) => (
            <p key={index} style={{ margin: '4px 0', color: entry.color }}>
              {entry.dataKey}: {entry.value}
              {entry.dataKey === 'engagementRate' && '%'}
            </p>
          ))}
        </div>
      );
    }
    return null;
  };

  return (
    <div>
      <h2>Engagement Analytics Dashboard</h2>

      {/* Metric Selection */}
      <div style={{ 
        display: 'flex', 
        justifyContent: 'center', 
        gap: '15px', 
        marginBottom: '30px',
        flexWrap: 'wrap'
      }}>
        {[
          { id: 'engagement-rate', label: 'Engagement Rate' },
          { id: 'trending-patterns', label: 'Trending Patterns' },
          { id: 'content-performance', label: 'Content Performance' }
        ].map(metric => (
          <button
            key={metric.id}
            onClick={() => setSelectedMetric(metric.id)}
            style={{
              padding: '12px 24px',
              border: 'none',
              borderRadius: '25px',
              background: selectedMetric === metric.id 
                ? 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)'
                : 'linear-gradient(135deg, #95a5a6 0%, #7f8c8d 100%)',
              color: 'white',
              cursor: 'pointer',
              fontWeight: '600',
              fontSize: '13px',
              textTransform: 'uppercase',
              letterSpacing: '1px',
              transition: 'all 0.3s ease',
              transform: selectedMetric === metric.id ? 'scale(1.05)' : 'scale(1)',
              boxShadow: selectedMetric === metric.id 
                ? '0 8px 20px rgba(102, 126, 234, 0.3)'
                : '0 4px 10px rgba(149, 165, 166, 0.2)'
            }}
          >
            {metric.label}
          </button>
        ))}
      </div>

      <div className="chart-container" style={{ 
        opacity: animationStep ? 1 : 0, 
        transform: animationStep ? 'translateY(0)' : 'translateY(20px)',
        transition: 'all 0.8s ease'
      }}>
        {selectedMetric === 'engagement-rate' && (
          <ResponsiveContainer width="100%" height="100%">
            <BarChart data={engagementData} margin={{ top: 20, right: 30, bottom: 40, left: 20 }}>
              <CartesianGrid strokeDasharray="3 3" stroke="rgba(102, 126, 234, 0.1)" />
              <XAxis dataKey="country" tick={{ fontSize: 12 }} />
              <YAxis tick={{ fontSize: 12 }} />
              <Tooltip content={<CustomTooltip />} />
              <Bar 
                dataKey="engagementRate" 
                fill="url(#colorGradient)" 
                radius={[4, 4, 0, 0]}
                animationDuration={1500}
              />
              <defs>
                <linearGradient id="colorGradient" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="5%" stopColor="#667eea" stopOpacity={0.9}/>
                  <stop offset="95%" stopColor="#764ba2" stopOpacity={0.6}/>
                </linearGradient>
              </defs>
            </BarChart>
          </ResponsiveContainer>
        )}

        {selectedMetric === 'trending-patterns' && (
          <ResponsiveContainer width="100%" height="100%">
            <AreaChart data={trendingPatterns} margin={{ top: 20, right: 30, bottom: 40, left: 20 }}>
              <CartesianGrid strokeDasharray="3 3" stroke="rgba(102, 126, 234, 0.1)" />
              <XAxis dataKey="time" tick={{ fontSize: 12 }} />
              <YAxis tick={{ fontSize: 12 }} />
              <Tooltip content={<CustomTooltip />} />
              <Area 
                type="monotone" 
                dataKey="engagement" 
                stroke="#667eea" 
                strokeWidth={3}
                fill="url(#areaGradient)"
                animationDuration={2000}
              />
              <defs>
                <linearGradient id="areaGradient" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="5%" stopColor="#667eea" stopOpacity={0.8}/>
                  <stop offset="95%" stopColor="#667eea" stopOpacity={0.1}/>
                </linearGradient>
              </defs>
            </AreaChart>
          </ResponsiveContainer>
        )}

        {selectedMetric === 'content-performance' && (
          <ResponsiveContainer width="100%" height="100%">
            <PieChart>
              <Pie
                data={contentCategories}
                cx="50%"
                cy="50%"
                innerRadius={80}
                outerRadius={140}
                paddingAngle={5}
                dataKey="value"
                animationDuration={1500}
              >
                {contentCategories.map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={entry.color} />
                ))}
              </Pie>
              <Tooltip 
                formatter={(value) => [`${value}%`, 'Performance']}
                contentStyle={{
                  backgroundColor: 'rgba(0, 0, 0, 0.9)',
                  color: 'white',
                  border: 'none',
                  borderRadius: '8px'
                }}
              />
            </PieChart>
          </ResponsiveContainer>
        )}
      </div>

      {/* Stats Cards */}
      <div style={{
        display: 'grid',
        gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))',
        gap: '20px',
        marginTop: '30px'
      }}>
        <div style={{
          background: 'linear-gradient(135deg, #f093fb 0%, #f5576c 100%)',
          color: 'white',
          padding: '20px',
          borderRadius: '15px',
          textAlign: 'center',
          boxShadow: '0 10px 25px rgba(240, 147, 251, 0.3)'
        }}>
          <h3 style={{ margin: '0 0 10px 0', fontSize: '1.8em' }}>
            {engagementData.reduce((sum, item) => sum + item.engagementRate, 0) / engagementData.length}%
          </h3>
          <p style={{ margin: 0, opacity: 0.9 }}>Avg Engagement</p>
        </div>

        <div style={{
          background: 'linear-gradient(135deg, #4facfe 0%, #00f2fe 100%)',
          color: 'white',
          padding: '20px',
          borderRadius: '15px',
          textAlign: 'center',
          boxShadow: '0 10px 25px rgba(79, 172, 254, 0.3)'
        }}>
          <h3 style={{ margin: '0 0 10px 0', fontSize: '1.8em' }}>
            {formatNumber(engagementData.reduce((sum, item) => sum + item.viewsPerVideo, 0) / engagementData.length)}
          </h3>
          <p style={{ margin: 0, opacity: 0.9 }}>Avg Views/Video</p>
        </div>

        <div style={{
          background: 'linear-gradient(135deg, #43e97b 0%, #38f9d7 100%)',
          color: 'white',
          padding: '20px',
          borderRadius: '15px',
          textAlign: 'center',
          boxShadow: '0 10px 25px rgba(67, 233, 123, 0.3)'
        }}>
          <h3 style={{ margin: '0 0 10px 0', fontSize: '1.8em' }}>95%</h3>
          <p style={{ margin: 0, opacity: 0.9 }}>Peak Time</p>
        </div>
      </div>
    </div>
  );
};

export default EngagementAnalytics;
